mapper.select:
select spic.id as rowId, spic.proj_id as initProjId, spin.name as initProjName, spic.changeitem as "changeitem.id",cspci.name as "changeitem.name", cspci.name as changeitemName, spic.old_value as oldValue, spic.new_value as newValue,spin.sub_no as subNo,luser.name as headName, cspcr.name as reasonName, spic.intro as intro, spic.data_status as dataStatus, suser.name as subUserName, spic.sub_date as subDate, spic.check_status as checkStatus, spic.serial_no as serialNo, spic.sys_no as sysNo, spic.note as note, spic.old_value_desc as oldValueDesc, spic.new_value_desc as newValueDesc from srm_projects_info_change spic left join srm_projects_info spin on spin.id=spic.proj_id left join ct_srm_project_change_item cspci on cspci.code=spic.changeitem left join ct_srm_user huser on huser.id=spic.creator left join ct_srm_user luser on luser.id=spin.head left join ct_srm_user suser on suser.id=spic.sub_user_id left join ct_srm_project_change_reason cspcr on cspcr.code=spic.reason where 1=1
and spin.sys_no=#{projectsInfoChangeDto.prjSysNo}
and spic.sys_no=#{projectsInfoChangeDto.sysNo}
order by spic.id desc
